import{_ as t,o as a,c as i,ao as r}from"./chunks/framework.BwTKejc4.js";const p=JSON.parse('{"title":"Working with large data","description":"","frontmatter":{},"headers":[],"relativePath":"model-guides/large-data.md","filePath":"model-guides/large-data.md","lastUpdated":null}'),s={name:"model-guides/large-data.md"};function o(n,e,l,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="Working-with-large-data" tabindex="-1">Working with large data <a class="header-anchor" href="#Working-with-large-data" aria-label="Permalink to &quot;Working with large data {#Working-with-large-data}&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Status — Stable</p><p>Mirrors drmTMB&#39;s <a href="https://itchyshin.github.io/drmTMB/articles/large-data.html" target="_blank" rel="noreferrer">Working with large data</a>. How DRM.jl stays fast as the number of units grows, and what to reach for when a model is large.</p></div><p>The selling-point model — the q=4 phylogenetic bivariate location–scale fit — is built to scale. The marginal likelihood is a <strong>sparse augmented-state Laplace approximation with an exact O(p) gradient</strong>: it never forms the dense p×p phylogenetic covariance, and it gets the gradient from a Takahashi selected inverse rather than by differentiating a dense factorisation. The practical consequence is near-linear scaling in the number of tips.</p><h2 id="Verified-scaling" tabindex="-1">Verified scaling <a class="header-anchor" href="#Verified-scaling" aria-label="Permalink to &quot;Verified scaling {#Verified-scaling}&quot;">​</a></h2><p>The biological per-dimension-variance model (a 4×4 Λ: a separate phylogenetic variance per axis plus cross-covariance, <code>nrep = 4</code> replicates) was timed end to end with the O(p) sparse-precision sampler:</p><table tabindex="0"><thead><tr><th style="text-align:right;">p (tips, ×4 obs)</th><th style="text-align:right;">wall</th><th style="text-align:right;">iters</th><th style="text-align:right;">per-obs logLik</th></tr></thead><tbody><tr><td style="text-align:right;">100</td><td style="text-align:right;">0.77 s</td><td style="text-align:right;">37</td><td style="text-align:right;">−2.09</td></tr><tr><td style="text-align:right;">1000</td><td style="text-align:right;">4.49 s</td><td style="text-align:right;">15</td><td style="text-align:right;">−2.36</td></tr><tr><td style="text-align:right;">5000</td><td style="text-align:right;">49.5 s</td><td style="text-align:right;">22</td><td style="text-align:right;">−2.35</td></tr><tr><td style="text-align:right;"><strong>10000</strong></td><td style="text-align:right;"><strong>112.9 s</strong></td><td style="text-align:right;">23</td><td style="text-align:right;">−2.61</td></tr></tbody></table><p>The fitted scaling exponent is <strong>k = 1.08 — near-perfect O(p)</strong>: iteration counts stay flat and the per-observation logLik is stable as <code>p</code> grows. These are reproduced numbers (<code>report/comparison-grid.md</code>); the harness is <code>bench/run_scaling.jl</code>.</p><div class="tip custom-block"><p class="custom-block-title">On head-to-head claims</p><p>The O(p) result above is measured for DRM.jl. A drmTMB head-to-head at <code>nrep = 4</code> / <code>p &gt; 100</code> was <strong>not</strong> run, so any &quot;N× faster at p = 10,000&quot; figure would be an extrapolation, not a measurement — this guide does not claim one. The measured single-fit comparison (same model, real data) is <strong>2.18× over drmTMB</strong>; see the <a href="./model-map">model map</a> and <code>HANDOVER.md</code>.</p></div><h2 id="Why-it-scales" tabindex="-1">Why it scales <a class="header-anchor" href="#Why-it-scales" aria-label="Permalink to &quot;Why it scales {#Why-it-scales}&quot;">​</a></h2><ul><li><p><strong>Sparse precision, never dense covariance.</strong> The phylogenetic prior precision is sparse (≈ 8p non-zeros for a binary tree). The engine factorises that sparse matrix with CHOLMOD; it never materialises the dense Σ.</p></li><li><p><strong>Exact O(p) gradient.</strong> The implicit-function gradient reuses a Takahashi selected inverse — the entries of the inverse that the sparse Cholesky already touches — instead of an O(p²) or O(p³) dense differentiation. This is the difference that lets the fit reach p = 10,000 with flat iteration counts.</p></li><li><p><strong>A precision sampler for uncertainty.</strong> Posterior draws of the random effects come from the same sparse precision (<code>Cov(û) ≈ P⁻¹</code>), so bootstrap and conditional-mode work stays O(p) too.</p></li></ul><h2 id="Practical-tips-for-large-fits" tabindex="-1">Practical tips for large fits <a class="header-anchor" href="#Practical-tips-for-large-fits" aria-label="Permalink to &quot;Practical tips for large fits {#Practical-tips-for-large-fits}&quot;">​</a></h2><ul><li><p><strong>Stay in ML.</strong> ML is the default and is comparable across fixed-effect structures — keep it for model selection on large data. REML is an option, not the default.</p></li><li><p><strong>Standardise covariates.</strong> Good conditioning matters more as <code>p</code> grows; centre and scale continuous predictors so the optimiser&#39;s Hessian stays well-behaved.</p></li><li><p><strong>Thread the bootstrap and the profile CIs.</strong> Parametric bootstrap replicates are independent refits; profile-likelihood endpoints are independent per coefficient. <code>confint(fit; method = :profile, threads = true)</code> profiles coefficients in parallel when the objective is thread-safe — set <code>JULIA_NUM_THREADS</code> to engage it.</p></li><li><p><strong>Check the fit cheaply.</strong> <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.check_drm"><code>check_drm</code></a> reports convergence and covariance conditioning without re-fitting — useful before committing to an expensive bootstrap.</p></li></ul><h2 id="Beyond-the-verified-engine" tabindex="-1">Beyond the verified engine <a class="header-anchor" href="#Beyond-the-verified-engine" aria-label="Permalink to &quot;Beyond the verified engine {#Beyond-the-verified-engine}&quot;">​</a></h2><p>The O(p) machinery lives in the verified phylogenetic engine. The non-Gaussian GLMM paths (Poisson/NB2/Beta/Gamma random effects via quadrature) are designed for moderate group counts rather than p = 10,000-scale phylogenies; for very large structured problems, the phylogenetic location–scale engine is the path that has been benchmarked to scale.</p>',14)])])}const f=t(s,[["render",o]]);export{p as __pageData,f as default};
